// Space: O(1)

class Solution {
public:
    int minStoneSum(vector<int>& piles, int k) {
        make_heap(begin(piles), end(piles));
        while (--k >= 0) {
            int x = piles.front();
            pop_heap(begin(piles), end(piles)); piles.pop_back();
            piles.emplace_back((x + 1) / 2);
            push_heap(begin(piles), end(piles));
        }
        return accumulate(cbegin(piles), cend(piles), 0);
    }
};

# Time:  O(n + klogn)
# Space: O(1)

import heapq


class Solution(object):
    def minStoneSum(self, piles, k):
        """
        :type piles: List[int]
        :type k: int
        :rtype: int
        """
        for i, x in enumerate(piles):
            piles[i] = -x
        heapq.heapify(piles)
        for i in xrange(k):
            heapq.heappush(piles, heapq.heappop(piles)//2)
        return -sum(piles)
